from dataclasses import dataclass, field
from datetime import date
from enum import Enum
from typing import Optional

class MilestoneStatus(Enum):
    PENDING   = "pending"
    IN_FLIGHT = "in_flight"
    ACHIEVED  = "achieved"
    DELAYED   = "delayed"

@dataclass
class IntegrationMilestone:
    milestone_id: str
    name: str
    description: str
    owning_team: str
    target_date: date
    gates: list[str]          # milestone IDs that must be ACHIEVED before this one starts
    status: MilestoneStatus = MilestoneStatus.PENDING
    actual_date: Optional[date] = None
    blocked_reason: str = ""

    def is_ready_to_start(self, achieved_ids: set[str]) -> bool:
        """Return True only when all gate milestones are achieved."""
        return all(g in achieved_ids for g in self.gates)

    def slip_days(self, as_of: date) -> int:
        if self.status == MilestoneStatus.ACHIEVED and self.actual_date:
            return max(0, (self.actual_date - self.target_date).days)
        if self.status != MilestoneStatus.ACHIEVED:
            return max(0, (as_of - self.target_date).days)
        return 0

@dataclass
class IntegrationPlan:
    program: str
    milestones: list[IntegrationMilestone] = field(default_factory=list)

    def achieved_ids(self) -> set[str]:
        return {m.milestone_id for m in self.milestones
                if m.status == MilestoneStatus.ACHIEVED}

    def blocked_milestones(self, as_of: date) -> list[IntegrationMilestone]:
        ach = self.achieved_ids()
        return [m for m in self.milestones
                if m.status == MilestoneStatus.PENDING
                and not m.is_ready_to_start(ach)]

    def ready_to_start(self, as_of: date) -> list[IntegrationMilestone]:
        ach = self.achieved_ids()
        return [m for m in self.milestones
                if m.status == MilestoneStatus.PENDING
                and m.is_ready_to_start(ach)]

@dataclass
class PartialGate:
    """Allows a milestone to start with partial gate completion."""
    milestone_id: str
    required_gates: list[str]   # all must be achieved for full start
    partial_gates: list[str]    # subset sufficient for partial work to begin
    partial_work_description: str

    def can_start_partial(self, achieved_ids: set[str]) -> bool:
        return all(g in achieved_ids for g in self.partial_gates)

    def can_start_full(self, achieved_ids: set[str]) -> bool:
        return all(g in achieved_ids for g in self.required_gates)


# Example: Product teams can begin integration scaffolding once M1 is ready,
# even if M2 (RAG) is still in progress — they can't do end-to-end tests,
# but they can wire up API calls and write unit tests with mock data.
m3_partial = PartialGate(
    milestone_id="M3",
    required_gates=["M1", "M2"],
    partial_gates=["M1"],
    partial_work_description=(
        "Wire API calls and write unit tests with mock RAG responses. "
        "Full integration testing starts once M2 is achieved."
    ),
)

ach = plan.achieved_ids()  # assume M1 achieved, M2 pending
if m3_partial.can_start_partial(ach):
    print(f"Partial start allowed: {m3_partial.partial_work_description}")
if m3_partial.can_start_full(ach):
    print("Full integration work can begin.")
